<template>
  <h1>RedRose живёт тут!</h1>
  <section v-if="author.length > 0" class="news">
    <useArticle :article="elem" v-for="elem in about" :key="elem.id"></useArticle>
    <useArticle :article="elem" v-for="elem in author" :key="elem.id"></useArticle>
  </section>
  <h3 v-else>Загружаем...</h3>
</template>

<script>
import useArticle from './useArticle.vue';
import supabase from '@/api/supabase';
export default {
    name: "useAuthorPage",
    components: {
      useArticle
    },
    data() {
      return {
        author: [],
        about: []
      }
    },
    mounted() {
      this.getAuthor()
      this.getAbout()
    },
    methods: {
      async getAuthor() {
        const { data } = await supabase.from("news").select().eq("type", "author")
        this.author.push(...data)
      },
      async getAbout() {
        const { data } = await supabase.from("news").select().limit(1).eq("type", "about")
        this.about.push(...data)
      }
    }
}
</script>

