<template>
  <h1>Последний патч: 0.8.23</h1>
  <div class="content">
    <div class="instructions">
      <section v-if="instructions.length > 0" >
        <div class="buttons">
          <a
            href="https://www.dropbox.com/pri/get/ACNL-RUS-PATCH.rar?_download_id=26834396728388436132877027502914439404805101541342331982659201095&_notify_domain=www.dropbox.com&_subject_uid=3473190080&w=AABVutHtoBCdh2ZkucsL-EtZ6FKqFe6ad_BWyQ_pzgaGAQ"
            download
            >Скачать патч</a
          >
          <a @click="isShowInstructions = !isShowInstructions">Инструкция</a>
        </div>
        <div class="instructions__text" v-if="isShowInstructions">
          <useArticle
            :article="ins"
            v-for="ins in instructions"
            :key="ins.id"
          ></useArticle>
        </div>
      </section>
      <h3 v-else>Загружаем...</h3>
    </div>
    <div class="patch-note">
      <useArticle :article="patchnote" v-for="patchnote in patchnotes" :key="patchnote.id"></useArticle>
    </div>
  </div>
</template>

<script>
import useArticle from "./useArticle.vue";

import supabase from "@/api/supabase";

export default {
  name: "useDownloadPage",
  props: ['isAllowed', 'isAuthed'],
  components: {
    useArticle,
  },
  data() {
    return {
      instructions: [],
      patchnotes: [],
      isShowInstructions: false,
    };
  },
  mounted() {
    this.getInstructions();
    this.getPatchNotes();
  },
  methods: {
    async getInstructions() {
      const { data } = await supabase
        .from("news")
        .select()
        .eq("type", "download");
      this.instructions.push(...data);
    },
    async getPatchNotes() {
      const { data } = await supabase.from("patch-note").select()
      this.patchnotes.push(...data)
    }
  },
};
</script>

