<template>
  <header>
    <a @click="$emit('changeTabAction', 'News')">{{ isMobile ? "" : "Прогресс" }}<i class="fa-solid fa-house mobile-icon fa-lg"></i></a>
    <a @click="$emit('changeTabAction', 'Download')">{{ isMobile ? "" : "Скачать" }}<i class="fa-solid fa-file-arrow-down mobile-icon fa-lg"></i></a>
    <a @click="$emit('changeTabAction', 'About')">{{ isMobile ? "" : "Контент" }}<i class="fa-solid fa-newspaper mobile-icon fa-lg"></i></a>
    <a @click="$emit('changeTabAction', 'Author')">{{ isMobile ? "" : "Автор" }}<i class="fa-solid fa-user mobile-icon fa-lg"></i></a>
  </header>
</template>

<script>
export default {
    name: 'useHeader',
    emits: ['chageTabAction'],
    data() {
      return {
        isMobile: false
      }
    },
    methods: {
      updateWidth() {
        window.innerWidth <= 427 ? this.isMobile = true : this.isMobile = false
      }
    },
    created() {
      window.addEventListener('resize', this.updateWidth)
      window.addEventListener('load', this.updateWidth)
    }
}
</script>

<style lang="scss">
    header {
      .mobile-icon {
        display: none;
      }
        display: flex;
        justify-content: center;
        gap: 50px;
        background-color: #1f2234;
        padding: 10px 0px;
        box-sizing: border-box;
        transition: .3s;
        a {
          padding: 8px 5px;
          border-radius: 5px;
          font-weight: 700;
          transition: background-color .3s;
          display: flex;
          justify-content: center;
          align-items: center;
          &:hover {
            transition: background-color .3s;
            background-color: #323547;
          }
        }
    }
    @media (max-width: 470px) {
      header {
        gap: 25px;
      }
    }
    @media (max-width: 425px) {
      header {
        position: fixed;
        bottom: 0;
        width: 100%;
        gap: 4rem;
        height: 50px;
        .mobile-icon {
          display: flex;
          justify-content: center;
          align-items: center;
        }
      }
    }
    @media (max-width: 330px) {
      header {
        gap: 2rem
      }
    }
</style>