<template>
  <h1>Ты кто?</h1>
  <div class="registration-form" v-if="formType">
      <form @submit.prevent="registerUser">
        <div class="email">
          <label for="login">Почта:</label>
          <input type="text" placeholder="Введите логин" v-model="email" />
        </div>
        <div class="pass">
          <label for="password">Пароль:</label>
          <input type="password" placeholder="Введите пароль" v-model="password" />
        </div>
        <div class="additional">
          <button type="submit">Зарегистрироваться</button>
          <span class="little">Уже есть аккаунт? <a @click="formType = false">Войдите!</a></span>
        </div>
        <div class="alert" :class="!isError ? 'error' : 'success'">
          <p>{{ alert }}</p>
        </div>
      <div class="progress-bar" :class="isSucceded ? 'show' : ''"></div>
      </form>
  </div>
  <div class="login-form" v-else>
    <form @submit.prevent="loginUser">
      <div class="email">
        <label for="login">Почта:</label>
        <input type="text" placeholder="Введите логин" v-model="email" />
      </div>
      <div class="pass">
        <label for="password">Пароль:</label>
        <input type="password" placeholder="Введите пароль" v-model="password" />
      </div>
      <div class="additional">
        <button type="submit">Войти</button>
        <span class="little">Впервые здесь? <a @click="formType = true">Зарегистрируйтесь!</a></span>
      </div>
      <div class="alert" :class="isError ? 'error' : 'success'">
        <p>{{ alert }}</p>
      </div>
      <div class="progress-bar" :class="isSucceded ? 'show' : ''"></div>
      </form>
  </div>
</template>

<script setup>
/* eslint-disable */
import supabase from "@/api/supabase";
import { ref } from "vue";

const email = ref("");
const password = ref("");
const formType = ref(false)

const alert = ref("")
const isError = ref(false)
const isSucceded = ref(false)

 async function registerUser() {
  const { data, error } = await supabase.auth.signUp({
    email: email.value,
    password: password.value,
  });
  if(data.user != null) {
    email.value = ""
    password.value = ""
    alert.value = "Успешно! Подтвердите аккаунт, пройдя по ссылке на почте!"
    isError.value = true
    isSucceded.value = true
    setTimeout(() => {
      alert.value = ''
      formType.value = false
      isSucceded.value = false
    }, 5000);
  }else if(data.user == null){
    isError.value = false
    alert.value = "Произошла непредвиденная ошибка. Попробуйте ещё раз."
    setTimeout(() => {
      alert.value = ''
    }, 5000);
  }
}

async function loginUser() {
    const { data, error } = await supabase.auth.signInWithPassword({
        email: email.value,
        password: password.value,
    })
    if(data != null) {
        window.location.reload()
    }
}


</script>

<style lang="scss" scoped>

.progress-bar{
  width: 100%;
  height: 2px;
  background-color: green;
  margin-top: 5px;
  animation: decrease 5s linear;
  animation-fill-mode: forwards;
  display: none;
  &.show {
    display: block;
  }
}

@keyframes decrease {
  0% {
    width: 100%;
  }
  100% {
    width: 0%;
  }
}
.little {
    opacity: .4;
    font-size: 14px;
    text-align: center;
    margin-top: -10px;
    a{ 
        text-decoration: underline;
    }
}
h1 {
    text-align: center;
}
.alert {
  font-size: 12px;
  text-align: center;
  &.success{
    p {
      color: green;
    }
  }
  &.error {
    p {
      color: red;
    }
  }
  p{
    transition: .3s;
    margin: 0px;
  }
}

.registration-form,
.login-form {
  max-width: 360px;
  width: 100%;
  padding: 20px;
  box-sizing: border-box;
  .email, .pass, .additional {
    display: flex;
    flex-direction: column;
    gap: 10px;
    padding: 10px 0px;
  }
  form {
    // display: flex;
    flex-direction: column;
    padding: 20px;
    gap: 20px;
    background-color: #202435;
    border-radius: 10px;
    box-sizing: border-box;
    input {
      background-color: #1f2234;
      border: 1px solid #323547;
      outline: none;
      height: 30px;
      border-radius: 5px;
      color: #c9cccf;
      padding-left: 10px;
    }
    button {
      background-color: #323547;
      border: none;
      outline: none;
      color: #c9cccf;
      height: 40px;
      border-radius: 5px;
      transition: .3s;
      &:hover {
        cursor: pointer;
        opacity: .7;
      }
    }
  }
}
</style>
